import { agentConfig } from '@mastra/core/agent'
import { csvToQuestionsWorkflow } from './workflows/csv-to-questions'

export default agentConfig({
  model: 'anthropic/claude-haiku-4-5',
  workflows: { csvToQuestionsWorkflow },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

// CSV parsing helper function
function parseCSVRow(row: string): string[] {
  const result: string[] = []
  let current = ''
  let inQuotes = false

  for (let i = 0; i < row.length; i++) {
    const char = row[i]

    if (char === '"' && !inQuotes) {
      inQuotes = true
    } else if (char === '"' && inQuotes) {
      inQuotes = false
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim())
      current = ''
    } else {
      current += char
    }
  }

  result.push(current.trim())
  return result
}

// Infer data type from sample value
function inferDataType(value: string): string {
  if (!value || value.trim() === '') {
    return 'empty/null'
  }

  // Check if it's a number
  if (!isNaN(Number(value)) && !isNaN(parseFloat(value))) {
    return Number.isInteger(Number(value)) ? 'integer' : 'decimal'
  }

  // Check if it's a date (basic check)
  const datePattern = /^\d{4}-\d{2}-\d{2}|\d{2}\/\d{2}\/\d{4}|\d{2}-\d{2}-\d{4}/
  if (datePattern.test(value)) {
    return 'date'
  }

  // Check if it's a boolean
  const lowerValue = value.toLowerCase()
  if (lowerValue === 'true' || lowerValue === 'false' || lowerValue === 'yes' || lowerValue === 'no') {
    return 'boolean'
  }

  return 'text'
}

export default createTool({
  id: 'fetch_csv',
  description: 'Downloads a CSV from a URL, parses it, and returns a comprehensive summary',
  inputSchema: z.object({
    url: z.string().url().describe('URL to the CSV file to download'),
  }),
  outputSchema: z.object({
    summary: z.string().describe('AI-generated summary of the CSV data'),
    fileSize: z.number().describe('Size of the downloaded file in bytes'),
    rowCount: z.number().describe('Number of rows in the CSV'),
    columnCount: z.number().describe('Number of columns in the CSV'),
    characterCount: z.number().describe('Number of characters in the original CSV'),
  }),
  execute: async (inputData) => {
    const { url } = inputData

    try {
      // Step 1: Download the CSV
      const response = await fetch(url)

      if (!response.ok) {
        throw new Error(`Failed to download CSV: ${response.status} ${response.statusText}`)
      }

      const csvText = await response.text()
      const csvBuffer = Buffer.from(csvText, 'utf-8')

      if (!csvText || csvText.trim().length === 0) {
        throw new Error('CSV file is empty')
      }

      // Step 2: Parse and analyze CSV
      const lines = csvText
        .split('\n')
        .map(line => line.trim())
        .filter(line => line.length > 0)
      const rowCount = lines.length
      const columnCount = rowCount > 0 ? parseCSVRow(lines[0]).length : 0

      if (rowCount === 0) {
        throw new Error('CSV has no valid rows')
      }

      // Create structured data analysis
      let structuredData = `CSV Data Analysis:\n`
      structuredData += `- Total Rows: ${rowCount}\n`
      structuredData += `- Total Columns: ${columnCount}\n`
      structuredData += `- File Size: ${csvBuffer.length} bytes\n\n`

      // Add column analysis
      if (rowCount > 0) {
        const headers = parseCSVRow(lines[0])
        structuredData += `Column Headers:\n`
        headers.forEach((header, index) => {
          structuredData += `${index + 1}. ${header}\n`
        })
        structuredData += '\n'
      }

      // Add data type analysis
      if (rowCount > 1) {
        const headers = parseCSVRow(lines[0])
        const sampleRow = parseCSVRow(lines[1])

        structuredData += `Data Type Analysis:\n`
        headers.forEach((header, index) => {
          const sampleValue = sampleRow[index] || ''
          const dataType = inferDataType(sampleValue)
          structuredData += `- ${header}: ${dataType} (sample: "${sampleValue}")\n`
        })
        structuredData += '\n'
      }

      // Add sample data
      const sampleRows = Math.min(5, rowCount)
      structuredData += `Sample Data (first ${sampleRows} rows):\n`

      for (let i = 0; i < sampleRows; i++) {
        const row = parseCSVRow(lines[i])
        if (i === 0) {
          structuredData += `Headers: ${row.join(' | ')}\n`
        } else {
          structuredData += `Row ${i}: ${row.join(' | ')}\n`
        }
      }

      if (rowCount > 5) {
        structuredData += `\n... and ${rowCount - 5} more rows\n`
      }

      return {
        summary: structuredData,
        fileSize: csvBuffer.length,
        rowCount,
        columnCount,
        characterCount: csvText.length,
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error'
      throw new Error(`Failed to process CSV from URL: ${errorMessage}`)
    }
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

const questionSchema = z.object({
  question: z.string(),
  answer_hint: z.string(),
  difficulty: z.enum(['easy', 'medium', 'hard']),
})

export default createTool({
  id: 'generate_questions',
  description: 'Uses an AI agent to generate quiz questions from CSV data',
  inputSchema: z.object({
    csv_text: z.string().describe('The raw CSV text to generate questions from'),
    num_questions: z.number().optional().default(5).describe('Number of questions to generate (5-10)'),
  }),
  outputSchema: z.object({
    questions: z.array(questionSchema),
  }),
  execute: async (inputData) => {
    const { csv_text, num_questions = 5 } = inputData
    const count = Math.max(5, Math.min(10, num_questions))

    const { mastra } = await import('@mastra/core')
    const agent = (mastra as any)?.getAgent('csvAgent')

    if (!agent) {
      throw new Error('Agent not available in Mastra context')
    }

    const response = await agent.generate(
      `Given the following CSV data, generate exactly ${count} quiz questions with varying difficulty levels.

CSV Data:
${csv_text.substring(0, 4000)}

Return ONLY a JSON array with this exact format (no markdown, no explanation):
[
  {
    "question": "Your question here",
    "answer_hint": "Brief hint about the answer",
    "difficulty": "easy" | "medium" | "hard"
  }
]

Include a mix of difficulties: some easy, some medium, some hard.`,
    )

    const text = response?.text || '[]'

    const jsonMatch = text.match(/\[[\s\S]*\]/)
    if (!jsonMatch) {
      throw new Error('Failed to parse questions from agent response')
    }

    const questions = JSON.parse(jsonMatch[0])

    return {
      questions: questions.map((q: any) => ({
        question: q.question || '',
        answer_hint: q.answer_hint || '',
        difficulty: ['easy', 'medium', 'hard'].includes(q.difficulty) ? q.difficulty : 'medium',
      })),
    }
  },
})

import { createWorkflow, createStep } from '@mastra/core/workflows'
import { z } from 'zod'

const downloadCsv = createStep({
  id: 'download-csv',
  description: 'Fetches CSV content from a URL',
  inputSchema: z.object({
    url: z.string().url(),
  }),
  outputSchema: z.object({
    url: z.string(),
    csvText: z.string(),
    rowCount: z.number(),
    columnCount: z.number(),
  }),
  execute: async ({ inputData }) => {
    const response = await fetch(inputData.url)
    if (!response.ok) {
      throw new Error(`Failed to download CSV: ${response.status} ${response.statusText}`)
    }
    const csvText = await response.text()
    if (!csvText || csvText.trim().length === 0) {
      throw new Error('CSV file is empty')
    }
    const lines = csvText.split('\n').map((l) => l.trim()).filter(Boolean)
    const rowCount = lines.length
    const columnCount = rowCount > 0 ? lines[0].split(',').length : 0
    return { url: inputData.url, csvText, rowCount, columnCount }
  },
})

const summarizeCsv = createStep({
  id: 'summarize-csv',
  description: 'Uses agent to summarize CSV data within token limits',
  inputSchema: z.object({
    url: z.string(),
    csvText: z.string(),
    rowCount: z.number(),
    columnCount: z.number(),
  }),
  outputSchema: z.object({
    url: z.string(),
    csvText: z.string(),
    summary: z.string(),
  }),
  execute: async ({ inputData, mastra }) => {
    const agent = mastra?.getAgent('csvAgent')
    const response = await agent?.generate(
      `Summarize the following CSV data (rows: ${inputData.rowCount}, columns: ${inputData.columnCount}).

CSV:
${inputData.csvText.substring(0, 4000)}

Provide a concise summary of the data structure, key columns, and notable patterns.`,
    )
    return {
      url: inputData.url,
      csvText: inputData.csvText,
      summary: response?.text ?? '',
    }
  },
})

const generateQuestions = createStep({
  id: 'generate-questions',
  description: 'Uses agent to generate analytical questions from CSV data',
  inputSchema: z.object({
    url: z.string(),
    csvText: z.string(),
    summary: z.string(),
  }),
  outputSchema: z.object({
    url: z.string(),
    summary: z.string(),
    questions: z.array(
      z.object({
        question: z.string(),
        answer_hint: z.string(),
        difficulty: z.enum(['easy', 'medium', 'hard']),
      }),
    ),
  }),
  execute: async ({ inputData, mastra }) => {
    const agent = mastra?.getAgent('csvAgent')
    const response = await agent?.generate(
      `Given the following CSV summary and data, generate 5 analytical questions with varying difficulty.

Summary:
${inputData.summary}

CSV Data (first rows):
${inputData.csvText.substring(0, 4000)}

Return ONLY a JSON array with this exact format (no markdown, no explanation):
[
  {
    "question": "Your question here",
    "answer_hint": "Brief hint about the answer",
    "difficulty": "easy" | "medium" | "hard"
  }
]`,
    )

    const text = response?.text || '[]'
    const jsonMatch = text.match(/\[[\s\S]*\]/)
    const questions = jsonMatch ? JSON.parse(jsonMatch[0]) : []

    return {
      url: inputData.url,
      summary: inputData.summary,
      questions: questions.map((q: any) => ({
        question: q.question || '',
        answer_hint: q.answer_hint || '',
        difficulty: ['easy', 'medium', 'hard'].includes(q.difficulty) ? q.difficulty : 'medium',
      })),
    }
  },
})

export const csvToQuestionsWorkflow = createWorkflow({
  id: 'csv-to-questions-workflow',
  inputSchema: z.object({
    url: z.string().url(),
  }),
  outputSchema: z.object({
    url: z.string(),
    summary: z.string(),
    questions: z.array(
      z.object({
        question: z.string(),
        answer_hint: z.string(),
        difficulty: z.enum(['easy', 'medium', 'hard']),
      }),
    ),
  }),
})
  .then(downloadCsv)
  .then(summarizeCsv)
  .then(generateQuestions)

csvToQuestionsWorkflow.commit()
